import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class SecurePathTraversalExample {
    public static void main(String[] args) {
        String fileName = args[0]; // User input
        String directory = "/path/to/directory/"; // Base directory

        try {
            File file = new File(directory + fileName);

            if (file.getCanonicalPath().startsWith(new File(directory).getCanonicalPath())) {
                FileInputStream fis = new FileInputStream(file);

                int data;
                while ((data = fis.read()) != -1) {
                    System.out.print((char) data);
                }

                fis.close();
            } else {
                System.out.println("Invalid file path specified.");
            }
        } catch (IOException e) {
            System.out.println("File not found or cannot be opened.");
        }
    }
}

